import{c as i,a7 as r,y as o,B as e,v as t,D as a}from"./chunks/framework.3cjvm90C.js";const c=JSON.parse('{"title":"DAPO: 一个开源的大规模 LLM 强化学习系统","description":"介绍DAPO算法的解耦裁剪与动态采样策略及其开源大规模强化学习训练系统","frontmatter":{"title":"DAPO: 一个开源的大规模 LLM 强化学习系统","description":"介绍DAPO算法的解耦裁剪与动态采样策略及其开源大规模强化学习训练系统"},"headers":[],"relativePath":"rlhf/paper/dapo.md","filePath":"rlhf/paper/dapo.md","lastUpdated":1782448598000}'),h={name:"rlhf/paper/dapo.md"};function n(m,l,p,_,s,$){return r(),o("div",null,[...l[0]||(l[0]=[e('<h1 id="dapo-一个开源的大规模-llm-强化学习系统" tabindex="-1">DAPO: 一个开源的大规模 LLM 强化学习系统 <a class="header-anchor" href="#dapo-一个开源的大规模-llm-强化学习系统" aria-label="Permalink to “DAPO: 一个开源的大规模 LLM 强化学习系统”">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to “摘要”">​</a></h2><p>推理扩展赋予了大语言模型（LLMs）前所未有的推理能力，而强化学习（RL）是激发复杂推理的核心技术。然而，当前最先进的推理 LLMs 的关键技术细节（如 OpenAI 的博客和 DeepSeek R1 技术报告）仍然被隐藏，导致社区难以复现其 RL 训练结果。我们提出了解耦裁剪和动态采样策略优化（DAPO）算法，并完全开源了一个最先进的大规模 RL 系统，该系统基于 Qwen2.5-32B 基础模型，在 AIME 2024 上取得了 50 分的成绩。与之前的工作不同，我们详细介绍了算法的四个关键技术，使得大规模 LLM RL 训练成为可能。此外，我们开源了基于 verl 框架的训练代码，并提供了一个精心整理和处理的数据集。这些开源组件增强了可复现性，并支持未来在大规模 LLM RL 领域的研究。</p><p>通讯作者： Qiying Yu，邮箱： <a href="mailto:yuqy22@mails.tsinghua.edu.cn" target="_blank" rel="noreferrer">yuqy22@mails.tsinghua.edu.cn</a></p><p>项目页面：</p><ul><li><a href="https://dapo-sia.github.io/" target="_blank" rel="noreferrer">https://dapo-sia.github.io/</a></li><li><a href="https://github.com/volcengine/verl" target="_blank" rel="noreferrer">https://github.com/volcengine/verl</a></li></ul><img src="https://github.com/BytedTsinghua-SIA/DAPO/raw/main/img/score.png" alt="alt text" style="zoom:33%;"><h2 id="_1-引言" tabindex="-1">1 引言 <a class="header-anchor" href="#_1-引言" aria-label="Permalink to “1 引言”">​</a></h2><p>测试时扩展（如 OpenAI 的 o1 [1]和 DeepSeek 的 R1 [2]）为大语言模型（LLMs）带来了深刻的范式转变 [3, 4, 5, 6, 7]。测试时扩展使得模型能够进行更长的链式思考（Chain-of-Thought），并诱导出复杂的推理行为，这使得模型在竞争性数学和编程任务（如 AIME 和 Codeforces）中表现出色。</p><p>推动这一变革的核心技术是大规模强化学习（RL），它能够激发复杂的推理行为，如自我验证和迭代优化。然而，现有的推理模型技术报告 [1, 8, 9, 10, 11, 2] 中隐藏了可扩展 RL 训练的实际算法和关键配方。在本文中，我们揭示了大规模 RL 训练中的重大障碍，并开源了一个可扩展的 RL 系统，包括完全开源的算法、训练代码和数据集，提供了具有工业级 RL 结果的民主化解决方案。</p><p>我们在 Qwen2.5-32B [12] 预训练模型上进行了 RL 实验。在最初的 GRPO 运行中，我们仅在 AIME 上取得了 30 分——这一表现显著低于 DeepSeek 的 RL （47 分）。深入分析表明，朴素的 GRPO 基线存在几个关键问题，如熵崩溃、奖励噪声和训练不稳定性。更广泛的社区在复现 DeepSeek 的结果时也遇到了类似的挑战 [13, 14, 15, 16, 17, 18, 19]，这表明 R1 论文中可能省略了开发工业级、大规模且可复现的 RL 系统所需的关键训练细节。</p><p>为了弥补这一差距，我们发布了一个开源的最先进的大规模 LLM RL 系统，该系统基于 Qwen2.5-32B 模型，在 AIME 2024 上取得了 50 分的成绩，超越了之前由 DeepSeek-R1-Zero-Qwen-32B [2] 取得的 47 分，且仅使用了 50% 的训练步骤（图 1）。我们提出了解耦裁剪和动态采样策略优化（DAPO）算法，并介绍了 4 个关键技术，使得 RL 在长链式思考（long-CoT） RL 场景中大放异彩。细节将在第 3 节中详细介绍。</p><ol><li>Clip-Higher，促进系统多样性，避免熵崩溃；</li><li>动态采样，提高训练效率和稳定性；</li><li>Token 级策略梯度损失，在长链式思考 RL 场景中至关重要；</li><li>过长奖励塑造，减少奖励噪声并稳定训练。</li></ol><p>我们的实现基于 verl [20]。通过完全开源我们的最先进 RL 系统，包括训练代码和数据，我们旨在揭示大规模 LLM RL 的宝贵见解，以惠及更广泛的社区。</p><h2 id="_2-预备知识" tabindex="-1">2 预备知识 <a class="header-anchor" href="#_2-预备知识" aria-label="Permalink to “2 预备知识”">​</a></h2><h3 id="_2-1-近端策略优化-ppo" tabindex="-1">2.1 近端策略优化（PPO） <a class="header-anchor" href="#_2-1-近端策略优化-ppo" aria-label="Permalink to “2.1 近端策略优化（PPO）”">​</a></h3><p>PPO [21] 引入了裁剪替代目标来进行策略优化。通过使用裁剪将策略更新限制在前一策略的近端区域内， PPO 稳定了训练并提高了样本效率。具体来说， PPO 通过最大化以下目标来更新策略：</p><p>$$ \\mathcal{J}<em>{\\textrm{PPO} }(\\theta)=\\mathbb{E}</em>{(q,a)\\sim\\mathcal{D},o_{\\leq t} \\sim\\pi_{\\theta,\\textrm{old} }(\\cdot|q)}\\left[\\min\\left(\\frac{\\pi_{\\theta}(o_{t}|q,o_{&lt;t})}{\\pi_{\\theta,\\textrm{old} }(o_{t}|q,o_{&lt;t})}\\hat{A}<em>{t},;\\operatorname{clip}\\left(\\frac{\\pi</em>{\\theta}(o_{t}|q,o_{&lt;t})}{\\pi_{\\theta,\\textrm{old} }(o_{t}|q,o_{&lt;t})},1-\\varepsilon,1+\\varepsilon\\right)\\hat{A}_{t}\\right)\\right] $$</p>',18),t("p",null,[a("其中$(q,a)$是来自数据分布$\\mathcal{D}$的问题-答案对，$\\varepsilon$是重要性采样比的裁剪范围，$\\hat{A}"),t("em",{t:""},"{t}$是时间步$t$的优势估计器。给定价值函数$V$和奖励函数$R$，$\\hat{A}"),a("$使用广义优势估计（GAE）[22]计算：")],-1),t("p",null,[a("$$ \\hat{A}^{\\textrm{GAE}(\\gamma,\\lambda)}"),t("em",{l:"0"},"{t}=\\sum"),a("^{\\infty}(\\gamma\\lambda)^{l}\\delta_{t+l}, $$")],-1),t("p",null,"其中",-1),t("p",null,"$$ \\delta_{l}=R_{l}+\\gamma V(s_{l+1})-V(s_{l}),\\quad 0\\leq\\gamma,\\lambda\\leq 1. $$",-1),t("h3",{id:"_2-2-组相对策略优化-grpo",tabindex:"-1"},[a("2.2 组相对策略优化（GRPO） "),t("a",{class:"header-anchor",href:"#_2-2-组相对策略优化-grpo","aria-label":"Permalink to “2.2 组相对策略优化（GRPO）”"},"​")],-1),t("p",null,[a("与 PPO 相比， GRPO 消除了价值函数，并以组相对的方式估计优势。对于特定问题-答案对$(q,a)$，行为策略$\\pi_{\\theta_{\\text{old} } }$采样一组$G$个独立响应${o_{i}}"),t("em",{i:""},"{i=1}^{G}$。然后，第$i$个响应的优势通过归一化组级奖励${R"),a("}_{i=1}^{G}$计算：")],-1),t("p",null,[a("$$ \\hat{A}"),t("em",{i:""},"{i,t}=\\frac{r"),a("-\\text{mean}({R_{i}}"),t("em",{i:""},"{i=1}^{G})}{\\text{std}({R"),a("}_{i=1}^{G})}. $$")],-1),t("p",null,"与 PPO 类似， GRPO 采用裁剪目标，并直接施加 KL 惩罚项：",-1),t("p",null,[a("$$ \\begin{aligned} \\mathcal{J}"),t("em",null,"{\\text{GRPO} }(\\theta) &= \\mathbb{E}"),a("{(q,a)\\sim\\mathcal{D},{o_{i}}"),t("em",null,"{i=1}^{G}\\sim\\pi"),a("{\\theta_{\\text{old} } }(\\cdot|q)} \\ &\\quad\\left[\\frac{1}{G}\\sum_{i=1}^{G}\\frac{1}{|o_{i}|}\\sum_{t=1}^{|o_{i}|}\\left(\\min\\left(r_{i,t}(\\theta)\\hat{A}"),t("em",{"i,t":""},"{i,t},\\text{clip}\\left(r"),a("(\\theta),1-\\varepsilon,1+\\varepsilon\\right)\\hat{A}"),t("em",null,"{i,t}\\right)-\\beta D"),a("{\\text{KL} }(\\pi_{\\theta}|\\pi_{\\text{ref} })\\right)\\right] \\end{aligned} $$")],-1),e('<p>其中</p><p>$$ r_{i,t}(\\theta)=\\frac{\\pi_{\\theta}(o_{i,t}\\mid q,o_{i,&lt;t})}{\\pi_{\\theta_{\\text{old} } }(o_{i,t}\\mid q,o_{i,&lt;t})}. $$</p><p>值得注意的是， GRPO 在样本级别计算目标。具体来说， GRPO 首先计算每个生成序列内的平均损失，然后再对不同样本的损失进行平均。正如我们将在第 3.3 节中讨论的那样，这种差异可能会对算法的性能产生影响。</p><h3 id="_2-3-移除-kl-散度" tabindex="-1">2.3 移除 KL 散度 <a class="header-anchor" href="#_2-3-移除-kl-散度" aria-label="Permalink to “2.3 移除 KL 散度”">​</a></h3><p>KL 惩罚项用于调节在线策略与冻结参考策略之间的差异。在 RLHF 场景 [23] 中， RL 的目标是在不偏离初始模型太远的情况下对齐模型行为。然而，在训练长链式思考推理模型时，模型分布可能会显著偏离初始模型，因此这种限制是不必要的。因此，我们将从我们提出的算法中排除 KL 项。</p><img src="https://arxiv.org/html/2503.14476v1/x2.png" alt="Refer to caption" style="zoom:33%;"><img src="https://arxiv.org/html/2503.14476v1/x3.png" alt="Refer to caption" style="zoom:33%;"><p>图 2：在 RL 训练过程中，应用 Clip-Higher 策略前后， AIME 测试集上的准确率以及 Actor 模型生成概率的熵。</p><h3 id="_2-4-基于规则的奖励建模" tabindex="-1">2.4 基于规则的奖励建模 <a class="header-anchor" href="#_2-4-基于规则的奖励建模" aria-label="Permalink to “2.4 基于规则的奖励建模”">​</a></h3><p>奖励模型的使用通常受到奖励欺骗问题的影响 [24, 25, 26, 27, 28, 29]。相反，我们直接使用可验证任务的最终准确率作为结果奖励，使用以下规则计算：</p><p>$$ R(\\hat{y},y)=\\begin{cases}1,&amp;\\texttt{is_equivalent}(\\hat{y},y)\\-1,&amp;\\text{否则}\\end{cases} $$</p><p>其中$y$是真实答案，$\\hat{y}$是预测答案。这种方法被证明是激活基础模型推理能力的有效方法，如自动定理证明 [30, 31, 32, 33]、计算机编程 [34, 35, 36, 37] 和数学竞赛 [2] 等多个领域所示。</p><h2 id="_3-dapo" tabindex="-1">3 DAPO <a class="header-anchor" href="#_3-dapo" aria-label="Permalink to “3 DAPO”">​</a></h2><p>我们提出了解耦裁剪和动态采样策略优化（DAPO）算法。DAPO 为每个问题$q$和答案$a$采样一组输出${o_{i}}_{i=1}^{G}$，并通过以下目标优化策略：</p>',14),t("p",null,[a("$$ \\begin{aligned} \\mathcal{J}"),t("em",null,"{\\text{DAPO} }(\\theta) &= \\mathbb{E}"),a("{(q,a)\\sim\\mathcal{D},{o_{i}}"),t("em",null,"{i=1}^{G}\\sim\\pi"),a("{\\theta_{\\text{old} } }(\\cdot|q)} \\ &\\quad\\left[\\frac{1}{\\sum_{t=1}^{G}|o_{i}|}\\sum_{i=1}^{G}\\sum_{t=1}^{|o_{i}|}\\min\\left(r_{i,t}(\\theta)\\hat{A}"),t("em",{"i,t":""},"{i,t},;\\operatorname{clip}\\left(r"),a("(\\theta),1-\\varepsilon_{\\text{low} },1+\\varepsilon_{\\text{high} }\\right)\\hat{A}"),t("em",{i:""},"{i,t}\\right)\\right] \\ &\\text{s.t. } 0<\\left|{o"),a("|\\texttt{is_equivalent}(a,o_{i})}\\right|<G \\end{aligned} $$")],-1),t("p",null,"其中",-1),t("p",null,[a("$$ r_{i,t}(\\theta)=\\frac{\\pi_{\\theta}(o_{i,t}\\mid q,o_{i,<t})}{\\pi_{\\theta_{\\text{old} } }(o_{i,t}\\mid q,o_{i,<t})},\\quad\\hat{A}"),t("em",{i:""},"{i,t}=\\frac{R"),a("-\\operatorname{mean}({R_{i}}"),t("em",{i:""},"{i=1}^{G})}{\\operatorname{std}({R"),a("}_{i=1}^{G})}. $$")],-1),t("p",null,"完整算法见算法 1。在本节中，我们将介绍与 DAPO 相关的关键技术。",-1),t("h3",{id:"_3-1-提高上限-clip-higher",tabindex:"-1"},[a("3.1 提高上限： Clip-Higher "),t("a",{class:"header-anchor",href:"#_3-1-提高上限-clip-higher","aria-label":"Permalink to “3.1 提高上限： Clip-Higher”"},"​")],-1),t("p",null,"在我们使用朴素 PPO [21] 或 GRPO [38] 的初始实验中，我们观察到了熵崩溃现象：随着训练的进行，策略的熵迅速下降（图 1(b)）。某些组的采样响应几乎完全相同。这表明探索有限且早期策略确定性，这可能会阻碍扩展过程。",-1),t("p",null,'我们提出了 Clip-Higher 策略来解决这个问题。裁剪重要性采样比在裁剪近端策略优化（PPO-Clip）[21] 中被引入，以限制信任区域并增强 RL 的稳定性。我们发现，上限裁剪会限制策略的探索。在这种情况下，使"利用 token"更有可能比提升不太可能的"探索 token"的概率要容易得多。',-1),t("p",null,"具体来说，当$\\varepsilon=0.2$（大多数算法的默认值）时，考虑两个动作，其概率分别为$\\pi_{\\theta_{\\text{old} } }(o_{i}\\mid q)=0.01$和$0.9$。更新后的最大可能概率$\\pi_{\\theta}(o_{i}\\mid q)$分别为$0.012$和$1.08$。这意味着对于概率较高的 token （例如$0.9$），约束较少。相反，对于低概率 token，实现非平凡的概率提升要困难得多。经验上，我们还观察到裁剪 token 的最大概率约为$\\pi_{\\theta}(o_{i}\\mid q)<0.2$（图 2(a)）。这一发现支持了我们的分析，即上限裁剪阈值确实限制了低概率 token 的概率提升，从而可能限制系统的多样性。",-1),t("p",null,"遵循 Clip-Higher 策略，我们将下限和上限裁剪范围解耦为$\\varepsilon_{\\text{low} }$和$\\varepsilon_{\\text{high} }$，如公式 10 所示：",-1),t("p",null,[a("$$ \\begin{align*} \\mathcal{J}"),t("em",null,"{\\mathrm{DAPO} }(\\theta) &= \\ \\mathbb{E}"),a("{(q,a)\\sim\\mathcal{D}, {\\mathbf{o}"),t("em",{i:"1"},"i}"),a("^G\\sim\\pi_{\\theta_{\\mathrm{old} } }(\\cdot|q)} \\ &\\qquad\\quad\\left[\\frac{1}{\\sum_{i=1}^G|\\mathbf{o}"),t("em",{i:"1"},"i|}\\sum"),a("^G\\sum_{t=1}^{|\\mathbf{o}"),t("em",{"i,t":""},"i|}\\min\\Big(r"),a("(\\theta)\\hat{A}"),t("em",{"i,t":""},"{i,t},\\ \\mathrm{clip}\\Big(r"),a("(\\theta),1-\\varepsilon_{\\mathrm{low} },1+\\varepsilon_{\\mathrm{high} }\\Big)\\hat{A}_{i,t}\\Big)\\right] \\ \\textrm{s.t.} &\\ \\ 0<\\left|{\\mathbf{o}_i \\mid \\mathbf{is_equivalent}(a,\\mathbf{o}_i)}\\right|<G. \\end{align*} \\tag{10} $$")],-1),t("p",null,"我们增加$\\varepsilon_{\\text{high} }$的值，为低概率 token 的提升留出更多空间。如图 2 所示，这一调整有效地增强了策略的熵，并促进了更多样化的样本生成。我们选择保持$\\varepsilon_{\\text{low} }$相对较小，因为增加它会将这些 token 的概率抑制到$0$，导致采样空间的崩溃。",-1),t("img",{src:"https://arxiv.org/html/2503.14476v1/x6.png",alt:"Refer to caption",style:{zoom:"33%"}},null,-1),t("img",{src:"https://arxiv.org/html/2503.14476v1/x7.png",alt:"Refer to caption",style:{zoom:"33%"}},null,-1),t("p",null,"图 4： Actor 模型生成概率分布的熵以及响应长度的变化。",-1),t("h3",{id:"_3-2-多多益善-动态采样",tabindex:"-1"},[a("3.2 多多益善：动态采样 "),t("a",{class:"header-anchor",href:"#_3-2-多多益善-动态采样","aria-label":"Permalink to “3.2 多多益善：动态采样”"},"​")],-1),t("p",null,"现有的 RL 算法在某些提示的准确率等于$1$时会遇到梯度下降问题。例如，对于 GRPO，如果某个提示的所有输出${\\alpha_{i}}_{i=1}^{G}$都正确并收到相同的奖励$1$，则该组的优势为零。零优势导致策略更新没有梯度，从而降低了样本效率。经验上，准确率等于$1$的样本数量不断增加，如图 3b 所示。这意味着每批次中有效提示的数量不断减少，这可能导致梯度方差增大，并削弱模型训练的梯度信号。",-1),t("p",null,"为此，我们提出过采样并过滤掉准确率等于 1 和 0 的提示，如公式 11 所示，保留批次中所有具有有效梯度的提示，并保持一致的提示数量。在训练前，我们持续采样，直到批次完全填充准确率既不为$0$也不为$1$的样本。",-1),t("p",null,[a("$$ \\begin{align*} \\mathcal{J}"),t("em",null,"{\\mathrm{DAPO} }(\\theta) &= \\ \\mathbb{E}"),a("{(q,a)\\sim\\mathcal{D}, {\\mathbf{o}"),t("em",{i:"1"},"i}"),a("^G\\sim\\pi_{\\theta_{\\mathrm{old} } }(\\cdot|q)} \\ &\\qquad\\quad\\left[\\frac{1}{\\sum_{i=1}^G|\\mathbf{o}"),t("em",{i:"1"},"i|}\\sum"),a("^G\\sum_{t=1}^{|\\mathbf{o}"),t("em",{"i,t":""},"i|}\\min\\Big(r"),a("(\\theta)\\hat{A}"),t("em",{"i,t":""},"{i,t},\\ \\mathrm{clip}\\Big(r"),a("(\\theta),1-\\varepsilon_{\\mathrm{low} },1+\\varepsilon_{\\mathrm{high} }\\Big)\\hat{A}_{i,t}\\Big)\\right] \\ \\textrm{s.t.} &\\ \\ 0<\\left|{\\mathbf{o}_i \\mid \\mathbf{is_equivalent}(a,\\mathbf{o}_i)}\\right|<G. \\end{align*} \\tag{10} $$")],-1),e('<p>请注意，这种策略不一定会阻碍训练效率，因为如果 RL 系统是同步的且生成阶段没有流水线化，生成时间通常由长尾样本的生成主导。此外，我们发现，使用动态采样的实验能够更快地达到相同的性能，如图 5 所示。</p><img src="https://arxiv.org/html/2503.14476v1/x8.png" alt="Refer to caption" style="zoom:33%;"><img src="https://arxiv.org/html/2503.14476v1/x9.png" alt="Refer to caption" style="zoom:33%;"><blockquote><p>图 5：应用<strong>过长奖励塑造</strong>策略前后，演员模型在 AIME 上的准确率及其生成概率的熵</p></blockquote><h3 id="_3-3-重新平衡-token-级策略梯度损失" tabindex="-1">3.3 重新平衡： Token 级策略梯度损失 <a class="header-anchor" href="#_3-3-重新平衡-token-级策略梯度损失" aria-label="Permalink to “3.3 重新平衡： Token 级策略梯度损失”">​</a></h3><p>原始的 GRPO 算法采用样本级损失计算，即首先在每个样本内按 token 平均损失，然后在样本间聚合损失。在这种方法中，每个样本在最终损失计算中被赋予相同的权重。然而，我们发现这种损失缩减方法在长链式思考 RL 场景中引入了几个挑战。</p><p>由于所有样本在损失计算中被赋予相同的权重，较长响应中的 token （包含更多 token）可能对整体损失的贡献不成比例地较低，这可能导致两个不利影响。首先，对于高质量的长样本，这种效应可能会阻碍模型学习其中的推理相关模式。其次，我们观察到，过长的样本通常表现出低质量模式，如胡言乱语和重复单词。因此，样本级损失计算由于无法有效惩罚长样本中的这些不良模式，导致熵和响应长度的不健康增加，如图 4(a)和图 4(b)所示。</p><p>我们在长链式思考 RL 场景中引入了 Token 级策略梯度损失来解决上述限制：</p>',8),t("p",null,[a("$$ \\begin{align*} \\mathcal{J}"),t("em",null,"{\\mathrm{DAPO} }(\\theta) &= \\ \\mathbb{E}"),a("{(q,a)\\sim\\mathcal{D}, {\\mathbf{o}"),t("em",{i:"1"},"i}"),a("^G\\sim\\pi_{\\theta_{\\mathrm{old} } }(\\cdot|q)} \\ &\\qquad\\quad\\left[\\frac{1}{\\sum_{i=1}^G|\\mathbf{o}"),t("em",{i:"1"},"i|}\\sum"),a("^G\\sum_{t=1}^{|\\mathbf{o}"),t("em",{"i,t":""},"i|}\\min\\Big(r"),a("(\\theta)\\hat{A}"),t("em",{"i,t":""},"{i,t},\\ \\mathrm{clip}\\Big(r"),a("(\\theta),1-\\varepsilon_{\\mathrm{low} },1+\\varepsilon_{\\mathrm{high} }\\Big)\\hat{A}_{i,t}\\Big)\\right] \\ \\textrm{s.t.} &\\ \\ 0<\\left|{\\mathbf{o}_i \\mid \\mathbf{is_equivalent}(a,\\mathbf{o}_i)}\\right|<G. \\end{align*} \\tag{10} $$")],-1),e('<p>在这种设置中，较长的序列可以对整体梯度更新产生更大的影响。此外，从单个 token 的角度来看，如果某种生成模式能够导致奖励的增加或减少，无论它出现在多长的响应中，它都会被同等程度地促进或抑制。</p><h3 id="_3-4-隐藏与寻找-过长奖励塑造" tabindex="-1">3.4 隐藏与寻找：过长奖励塑造 <a class="header-anchor" href="#_3-4-隐藏与寻找-过长奖励塑造" aria-label="Permalink to “3.4 隐藏与寻找：过长奖励塑造”">​</a></h3><p>在 RL 训练中，我们通常为生成设置最大长度，过长的样本会被截断。我们发现，对截断样本的不当奖励塑造会引入奖励噪声，并显著干扰训练过程。</p><p>$$ R_{\\text{length} }(y)=\\begin{cases} 0, &amp; |y|\\leq L_{\\max}-L_{\\text{cache} } \\ \\frac{(L_{\\max}-L_{\\text{cache} })-|y|}{L_{\\text{cache} } }, &amp; L_{\\max}-L_{\\text{cache} }&lt;|y|\\leq L_{\\max} \\ -1, &amp; L_{\\max}&lt;|y| \\end{cases} \\tag{13} $$</p><p>我们进一步提出<strong>软过长惩罚</strong>（公式 13），这是一种长度感知的惩罚机制，用于塑造截断样本的奖励。具体而言，当响应长度超过预定义的最大值时，我们定义一个惩罚区间：</p><ul><li><strong>无惩罚区</strong>：若 $|y| \\leq L_{\\max} - L_{\\text{cache} }$，奖励无衰减。</li><li><strong>线性惩罚区</strong>：若 $L_{\\max} - L_{\\text{cache} } &lt; |y| \\leq L_{\\max}$，惩罚随长度线性增加。</li><li><strong>硬截断区</strong>：若 $|y| &gt; L_{\\max}$，施加固定惩罚 $-1$。</li></ul><p>此惩罚将与基于规则的正确性奖励叠加，从而引导模型避免生成过长的响应。</p><h4 id="算法-1-dapo-——解耦裁剪与动态采样策略优化" tabindex="-1">算法 1： DAPO ——解耦裁剪与动态采样策略优化 <a class="header-anchor" href="#算法-1-dapo-——解耦裁剪与动态采样策略优化" aria-label="Permalink to “算法 1： DAPO ——解耦裁剪与动态采样策略优化”">​</a></h4>',8),t("ol",null,[t("li",null,[t("strong",null,"输入"),a("：初始策略模型 $\\pi_{\\theta}$，奖励模型 $R$，任务提示集 $\\mathcal{D}$，超参数 $\\varepsilon_{\\text{low} }, \\varepsilon_{\\text{high} }$")]),t("li",null,[t("strong",null,"训练循环"),a("（共 $M$ 步）： "),t("ol",null,[t("li",null,"从 $\\mathcal{D}$ 中采样一个批次 $\\mathcal{D}_b$"),t("li",null,"更新旧策略模型 $\\pi_{\\theta_{\\text{old} } } \\leftarrow \\pi_{\\theta}$"),t("li",null,[a("对每个问题 $q \\in \\mathcal{D}"),t("em",null,[a("b$，采样 $G$ 个输出 ${\\mathbf{o}"),t("em",{i:"1"},"i}"),a("^G \\sim \\pi")]),a("{\\theta_{\\text{old} } }(\\cdot|q)$")]),t("li",null,[a("通过 $R$ 计算每个输出 $\\mathbf{o}"),t("em",{i:"1"},"i$ 的奖励 ${r_i}"),a("^G$")]),t("li",null,[a("过滤 $\\mathbf{o}_i$ 并将剩余样本加入动态采样缓冲区（"),t("strong",null,"动态采样"),a("，公式 11）")]),t("li",null,[t("strong",null,"若缓冲区大小 $n_b < N$"),a("： "),t("ul",null,[t("li",null,[a("对缓冲区中的每个 $\\mathbf{o}"),t("em",{"i,t":""},"i$，计算其第 $t$ 个 token 的优势 $\\hat{A}"),a("$（公式 9）")])])]),t("li",null,[t("strong",null,"参数更新循环"),a("（共 $\\mu$ 次迭代）： "),t("ul",null,[t("li",null,"通过最大化 DAPO 目标（公式 8）更新策略模型 $\\pi_{\\theta}$")])])])])],-1),e('<h3 id="_3-5-数据集转换" tabindex="-1">3.5 数据集转换 <a class="header-anchor" href="#_3-5-数据集转换" aria-label="Permalink to “3.5 数据集转换”">​</a></h3><p>我们的数据集来自 AoPS1 网站和官方竞赛主页，通过网页抓取和手动注释相结合的方式获取。数学数据集的答案通常以多种格式呈现，如表达式、公式和数字，这使得设计全面的解析规则具有挑战性。为了使用规则提供准确的奖励信号并最小化公式解析器引入的错误，受 AIME 启发，我们选择并将答案转换为易于解析的整数。例如，如果原始答案以$\\frac{a+\\sqrt{b} }{2}$的形式表示，我们指示 LLM 修改问题，使预期答案变为$a+b+c$。经过选择和转换，我们获得了 DAPO-Math-17K 数据集，该数据集包含 17K 个提示，每个提示都配有一个整数作为答案。</p><h2 id="_4-实验" tabindex="-1">4 实验 <a class="header-anchor" href="#_4-实验" aria-label="Permalink to “4 实验”">​</a></h2><h3 id="_4-1-训练细节" tabindex="-1">4.1 训练细节 <a class="header-anchor" href="#_4-1-训练细节" aria-label="Permalink to “4.1 训练细节”">​</a></h3><p>在这项工作中，我们特别关注数学任务以评估我们的算法，该算法可以轻松转移到其他任务。我们采用 verl 框架 [20] 进行训练。我们使用朴素的 GRPO [38] 作为基线算法，并使用组奖励归一化来估计优势。</p><p>对于超参数，我们使用 AdamW [39] 优化器，恒定学习率为$1\\times 10^{-6}$，并在 20 个 rollout 步骤中进行线性预热。对于 rollout，提示批次大小为 512，我们为每个提示采样 16 个响应。对于训练，小批次大小设置为 512，即每个 rollout 步骤进行 16 次梯度更新。对于<strong>过长奖励塑造</strong>，我们将预期最大长度设置为 16,384 个 token，并分配额外的 4,096 个 token 作为软惩罚缓存。因此，生成的最大 token 数设置为 20,480 个 token。至于<strong>Clip-Higher</strong>机制，我们将裁剪参数$\\varepsilon_{\\text{low} }$设置为 0.2，$\\varepsilon_{\\text{high} }$设置为 0.28，这有效地平衡了探索与利用之间的权衡。对于 AIME 的评估，我们重复评估集 32 次，并报告 avg@32 以确保结果稳定性。评估的推理超参数设置为温度 1.0 和 topp 0.7。</p><p><img src="https://arxiv.org/html/2503.14476v1/x10.png" alt="Refer to caption"></p><h3 id="_4-2-主要结果" tabindex="-1">4.2 主要结果 <a class="header-anchor" href="#_4-2-主要结果" aria-label="Permalink to “4.2 主要结果”">​</a></h3><p>在 AIME 2024 上的实验表明，<strong>DAPO</strong>成功地将 Qwen-32B 基础模型训练为一个强大的推理模型，其性能优于 DeepSeek 在 Qwen2.5-32B 上使用 R1 方法的实验。在图 1 中，我们观察到 AIME 2024 上的性能显著提升，准确率从接近 0% 提高到 50% 。值得注意的是，这一提升仅使用了 DeepSeek-R1-Zero-Qwen-32B 所需训练步骤的 50% 。</p><p>我们分析了我们方法中每种训练技术的贡献，详见表 1。观察到的改进证明了这些技术在 RL 训练中的有效性，每种技术都为 AIME 2024 贡献了几个准确率点。值得注意的是，在朴素的 GRPO 设置下，仅能从 Qwen2.5-32B 基础模型训练中达到 30% 的准确率。</p><p>对于 token 级损失，尽管它带来的性能提升较少，但我们发现它增强了训练稳定性，并使长度增长更加健康。</p><p>当应用<strong>动态采样</strong>时，尽管由于过滤掉零梯度数据需要采样更多数据，但总体训练时间并未显著受到影响。如图 6 所示，尽管采样实例数量增加，但由于所需的训练步骤减少，模型的收敛时间甚至缩短了。</p><h3 id="_4-3-训练动态" tabindex="-1">4.3 训练动态 <a class="header-anchor" href="#_4-3-训练动态" aria-label="Permalink to “4.3 训练动态”">​</a></h3><p>大规模语言模型的强化学习不仅是一个前沿的研究方向，也是一个本质上复杂的系统工程挑战，其特征是各个子系统之间的相互依赖性。对任何单个子系统的修改都可能通过系统传播，由于这些组件之间的复杂相互作用，导致不可预见的后果。即使初始条件的微小变化，如数据和超参数的变化，也可能通过迭代强化学习过程放大，产生结果的显著偏差。这种复杂性常常使研究人员面临一个困境：即使经过细致的分析和有根据的预期，认为某个修改将增强训练过程的特定方面，实际结果往往与预期轨迹不同。因此，在实验过程中监控关键的中间结果对于快速识别差异的来源并最终优化系统至关重要。</p><ul><li><strong>生成响应的长度</strong>是与训练稳定性和性能密切相关的指标，如图(a)a 所示。长度的增加为模型提供了更大的探索空间，允许采样更复杂的推理行为，并通过训练逐渐加强。然而，需要注意的是，长度在训练过程中并不总是保持持续上升的趋势。在某些相当长的时间内，它可能会表现出停滞甚至下降的趋势，这也已在 [] 中得到了证明。我们通常将长度与验证准确率结合使用，作为评估实验是否恶化的指标。</li><li><strong>训练过程中的奖励动态</strong>一直是强化学习中的关键监控指标之一，如图(b)b 所示。在我们的大多数实验中，奖励增加的趋势相对稳定，不会因实验设置的调整而显著波动或下降。这表明，在可靠的奖励信号下，语言模型能够稳健地拟合训练集的分布。然而，我们发现训练集上的最终奖励通常与验证集上的准确率几乎没有相关性，这表明对训练集的过拟合。</li><li><strong>Actor 模型和生成概率的熵</strong>与模型的探索能力相关，是我们实验中密切监控的关键指标。直观上，模型的熵需要保持在适当的范围内。过低的熵表明概率分布过于尖锐，导致探索能力丧失。相反，过高的熵通常与过度探索问题相关，如胡言乱语和重复生成。对于生成概率，情况正好相反。正如第 3.1 节所示，通过应用 Clip-Higher 策略，我们有效地解决了熵崩溃问题。在后续实验中，我们发现保持熵的缓慢上升趋势有助于模型性能的提升，如图 7c 和图 7d 所示。</li></ul><img src="https://arxiv.org/html/2503.14476v1/x11.png" alt="Refer to caption" style="zoom:33%;"><img src="https://arxiv.org/html/2503.14476v1/x12.png" alt="Refer to caption" style="zoom:33%;"><img src="https://arxiv.org/html/2503.14476v1/x13.png" alt="Refer to caption" style="zoom:33%;"><img src="https://arxiv.org/html/2503.14476v1/x14.png" alt="Refer to caption" style="zoom:33%;"><p>图 7：<strong>DAPO</strong>的响应长度、奖励分数、生成熵和平均概率的指标曲线，展示了 RL 训练的动态，并作为识别潜在问题的重要监控指标。</p><h3 id="_4-4-案例研究" tabindex="-1">4.4 案例研究 <a class="header-anchor" href="#_4-4-案例研究" aria-label="Permalink to “4.4 案例研究”">​</a></h3><p>在 RL 训练过程中，我们观察到一个有趣的现象： Actor 模型的推理模式随着时间的推移动态演变。具体来说，算法不仅加强了有助于正确解决问题的现有推理模式，还逐渐产生了最初不存在的新推理模式。这一发现揭示了 RL 算法的适应性和探索能力，并为模型的学习机制提供了新的见解。</p><p>例如，在模型训练的早期阶段，几乎没有出现对先前推理步骤的检查和反思。然而，随着训练的进行，模型表现出明显的反思和回溯行为，如表 2 所示。这一观察为进一步探索 RL 过程中推理能力的出现提供了新的视角，我们将其留给未来的研究。</p><h2 id="_5-结论" tabindex="-1">5 结论 <a class="header-anchor" href="#_5-结论" aria-label="Permalink to “5 结论”">​</a></h2><p>在本文中，我们发布了一个完全开源的大规模 LLM RL 系统，包括算法、代码基础设施和数据集。该系统实现了最先进的大规模 LLM RL 性能（使用 Qwen-32B 预训练模型在 AIME 上取得 50 分）。我们提出了<strong>解耦裁剪和动态采样策略优化（DAPO）</strong>算法，并介绍了 4 个关键技术，使得 RL 在长链式思考 RL 场景中强大且高效。此外，通过开源训练代码和数据集，我们为更广泛的研究社区和社会提供了实用的可扩展强化学习解决方案，使所有人都能从这些进步中受益。</p>',25)])])}const d=i(h,[["render",n]]);export{c as __pageData,d as default};
